def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        weight_factors = [0.95, 1.05, 0.9, 1.1, 0.85, 1.15, 0.8, 1.2, 0.75]
        for j in range(1, 10):
            term = (1 / (j**3)) * (ratio ** j) * weight_factors[j-1]
            if j % 3 == 0:
                term *= 1.25
            elif j % 4 == 0:
                term *= 0.85
            score += term
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 2.5
        elif remaining < 0.1 * capacity:
            score *= 1.7
        elif remaining < 0.25 * capacity:
            score *= 1.1
        else:
            score *= 0.75
        mod3 = int(capacity) % 3
        mod5 = int(capacity) % 5
        mod7 = int(capacity) % 7
        if mod3 == 0 and mod7 == 0:
            score -= 0.08 * (capacity / 8)
        elif mod5 == 0 or mod7 == 0:
            score -= 0.12 * (capacity / 15)
        else:
            score -= 0.03 * (capacity / 40)
        penalty = 0
        for k in range(1, 6):
            if abs(capacity - item * k) < 0.015 * capacity:
                penalty += 0.15 * (k**1.5)
        for m in range(2, 5):
            if (capacity % m == 0) and (item > capacity / (2 * m)):
                penalty -= 0.05 * m
        score += penalty
        if score < 0:
            score = 0
        if capacity > 100:
            score *= 1.2
        elif capacity < 20:
            score *= 0.8
        priorities[i] = score
    return priorities
